**vite.config.js**:

```javascript
import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

const analyzeMode = process.env.ANALYZE === 'true';

export default defineConfig(async () => {
  const visualizerPlugin = analyzeMode
    ? (await import('rollup-plugin-visualizer')).visualizer({
        filename: 'dist/bundle-report.html',
        gzipSize: true,
      })
    : null;

  return {
    plugins: [
      react({ jsxRuntime: 'automatic' }),
      visualizerPlugin,
    ].filter(Boolean),
    root: '.',
    base: '/',
    build: {
      outDir: 'dist',
      assetsDir: 'assets',
      sourcemap: false,
      rollupOptions: {
        output: {
          manualChunks: {
            vendor: ['react', 'react-dom'],
          },
        },
      },
    },
    server: {
      proxy: {
        '/api': {
          target: 'http://localhost:8000',
          changeOrigin: true,
        },
      },
    },
  };
});
```

Feature screens are code-split via `React.lazy()` dynamic imports. Vite/Rollup automatically creates separate chunks for each dynamic import тАФ no need for manual chunk definitions for feature screens. The `manualChunks` config only forces `react`+`react-dom` into a single vendor chunk for optimal caching.

