  --space-12: 3rem;      /* 48px */
  --space-16: 4rem;      /* 64px */
  --space-20: 5rem;      /* 80px */

  --touch-target-min: 2.75rem; /* 44px тАФ WCAG 2.5.5 / 2.5.8 */
